# {Implement a decentralized decision-making algorithm where each truck dynamically predicts potential future congestion at customer locations based on the expected arrival times of other trucks, thereby avoiding likely delays and optimizing the overall completion time.}
def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    congestion_threshold = 2  # Threshold for potential congestion
    min_weighted_cost = float('inf')
    best_node = None

    # Calculate future projection of congestion at each customer location
    future_arrival_times = np.zeros(len(unvisited_customers))
    for i, customer_pos in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            if not np.array_equal(truck_pos, cur_truck_pos):
                travel_time = euclidean_distance(truck_pos, customer_pos) / truck_speed
                projected_arrival_time = current_time + travel_time
                if projected_arrival_time <= time_windows[i][1]:
                    future_arrival_times[i] += 1

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = euclidean_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time

        start_time, end_time = time_windows[i]
        wait_time = max(0, start_time - arrival_time)

        penalty = max(0, 1000 * (arrival_time - end_time))

        # Include future projection of congestion in cost calculation
        congestion_penalty = 100 * (future_arrival_times[i] - congestion_threshold if future_arrival_times[i] > congestion_threshold else 0)

        cost = travel_time + wait_time
        weighted_cost = cost + congestion_penalty + penalty

        if weighted_cost < min_weighted_cost:
            min_weighted_cost = weighted_cost
            best_node = i

    return best_node
